import java.util.HashMap;

public class Main {
    public static void main(String[] args) {
        HashMap<String, Integer> scores = new HashMap<>();
        scores.put("Alice", 90);

        System.out.println(scores.getOrDefault("Alice", 0));  // 90
        System.out.println(scores.getOrDefault("Bob", 0));    // 0

        // Increment pattern
        scores.put("Alice", scores.getOrDefault("Alice", 0) + 10);
        System.out.println(scores.get("Alice"));               // 100
    }
}

